class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable now returns null for
        // empty env vars on Unix. Use string.IsNullOrEmpty to preserve the old
        // "not set" vs "empty" distinction, or call getenv directly via P/Invoke.
        // Here we need to distinguish "not set" from "explicitly empty", so we
        // use a P/Invoke to the native getenv which still differentiates them.
        var val = NativeGetEnv("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }

    // .NET 9+: Environment.GetEnvironmentVariable returns null for empty values
    // on Unix. Native getenv preserves the distinction (null = unset, "" = empty).
    [System.Runtime.InteropServices.DllImport("libc")]
    private static extern IntPtr getenv(string name);

    private static string? NativeGetEnv(string name)
    {
        IntPtr ptr = getenv(name);
        if (ptr == IntPtr.Zero)
            return null;
        return System.Runtime.InteropServices.Marshal.PtrToStringUTF8(ptr);
    }
}

